INSERT INTO businesses (id, name, category, description, phone, whatsapp, lat, lng, image, delivery_time, delivery_fee, min_order, rating, open_time, close_time, is_active, vertical) VALUES
('00000000-0000-0000-0000-000000000001', 'La Quincha', 'food', 'Traditional Panamanian dishes with a modern twist. Fresh seafood, vibrant atmosphere, community feel. The real deal in Venao.', '50766123401', '50766123401', 7.4210, -80.1501, 'https://images.unsplash.com/photo-1559339352-11d035aa65de?w=800&q=80', '25–35', 2, 8, 5.0, 11, 22, true, 'food'),
('00000000-0000-0000-0000-000000000002', 'Coleos Cafe', 'food', 'The surprise of Venao. Mediterranean-Asian fusion — hummus, pad Thai, kebabs, fresh local ingredients. Best coffee on the peninsula.', '50766234512', '50766234512', 7.4213, -80.1499, 'https://images.unsplash.com/photo-1554118811-1e0d58224f24?w=800&q=80', '20–30', 2, 10, 4.7, 7, 21, true, 'food'),
('00000000-0000-0000-0000-000000000003', 'El Sitio Restaurant', 'food', 'Right on the sand at El Sitio Hotel. Ceviche, grilled fish, cold beer. The original post-surf spot. Laid back, no pretense.', '50766345623', '50766345623', 7.4208, -80.1510, 'https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=800&q=80', '15–25', 0, 8, 4.1, 10, 23, true, 'food'),
('00000000-0000-0000-0000-000000000004', 'La Hummuseria', 'food', 'Hummus, falafel, and Middle Eastern bowls in a chill spot with board games. Surprisingly great for Panama. Vegan and meat options.', '50766456734', '50766456734', 7.4217, -80.1505, 'https://images.unsplash.com/photo-1540189549336-e6e99c3679fe?w=800&q=80', '20–30', 2, 10, 4.9, 12, 21, true, 'food'),
('00000000-0000-0000-0000-000000000005', 'Pizza Gavilan', 'food', E'Wood-fired pizza with a beachfront view. The most consistent pizza in Venao — good by any standard, great by Panama''s.', '50766567845', '50766567845', 7.4219, -80.1498, 'https://images.unsplash.com/photo-1513104890138-7c749659a591?w=800&q=80', '25–40', 2, 12, 4.3, 17, 22, true, 'food'),
('00000000-0000-0000-0000-000000000006', 'Wao Beach Bar', 'drinks', 'Beachfront bar with the best sunset view in Venao. Creative cocktails, cold beer, and a playlist that fits the vibe.', '50766678956', '50766678956', 7.4206, -80.1512, 'https://images.unsplash.com/photo-1514362545857-3bc16c4c7d1b?w=800&q=80', '10–20', 0, 5, 5.0, 14, 0, true, 'food'),
('00000000-0000-0000-0000-000000000007', 'Minisuper Venao', 'grocery', E'The town store. Beer, water, snacks, sunscreen, fresh fruit. Everything you need, nothing you don''t.', '50766789067', '50766789067', 7.4215, -80.1503, 'https://images.unsplash.com/photo-1490474418585-ba9bad8fd0ea?w=800&q=80', '15–25', 1, 5, 4.2, 7, 21, true, 'food'),
('00000000-0000-0000-0000-000000000008', 'Venao Wellness', 'massage', 'Sports massage, Swedish relaxation, yoga sessions. Beach or bungalow delivery. Book in advance for sunset slots.', '50766890178', '50766890178', 7.4222, -80.1507, 'https://images.unsplash.com/photo-1544161515-4ab6ce6db874?w=800&q=80', 'On request', 0, 40, 4.8, 8, 20, true, 'food'),
('00000000-0000-0000-0000-000000000009', 'El Sitio Surf School', 'surf', 'The original Venao surf school. Board rental, group lessons, private coaching. All levels welcome.', '50766901289', '50766901289', 7.4207, -80.1511, 'https://images.unsplash.com/photo-1455729552865-3658a5d39692?w=800&q=80', 'On request', 0, 20, 4.6, 6, 18, true, 'food'),
('00000000-0000-0000-0000-000000000010', 'Shaqui Venao Surf School', 'surf', 'One of the most popular surf schools in Playa Venao. Shaqui and his team know every wave. Fun, relaxed vibe. All levels welcome.', '50766910200', '50766910200', 7.4209, -80.1513, 'https://images.unsplash.com/photo-1502680390469-be75c86b636f?w=800&q=80', 'On request', 0, 40, 4.9, 6, 17, true, 'experience'),
('00000000-0000-0000-0000-000000000011', 'El Balo Restaurant', 'food', 'El Balo is a Venao institution. Grilled meats, fresh seafood, cold beer. No frills, all flavor. The kind of place you go back to every day.', '50766920300', '50766920300', 7.4214, -80.1508, 'https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=800&q=80', '20–35', 2, 10, 4.6, 11, 23, true, 'food'),
('00000000-0000-0000-0000-000000000012', 'Surf Dogo', 'surf', 'Local crew, good vibes, no ego. Surf Dogo makes learning to surf actually fun. Small groups, personal attention, best waves.', '50766930400', '50766930400', 7.4211, -80.1509, 'https://images.unsplash.com/photo-1517699418-0999eb78d0c0?w=800&q=80', 'On request', 0, 35, 4.8, 6, 18, true, 'experience'),
('00000000-0000-0000-0000-000000000013', 'Motek Ice Cream', 'food', 'Tropical ice cream and sorbets made fresh daily. Exotic local flavors — maracuyá, guanábana, coco, mamey. The sweetest stop in Venao.', '50766940500', '50766940500', 7.4216, -80.1506, 'https://images.unsplash.com/photo-1501443762994-82bd5dace89a?w=800&q=80', '10–20', 1, 4, 4.9, 11, 21, true, 'food'),
-- Experiences
('00000000-0000-0000-0000-0000000000e1', 'Playa Venao Surf School', 'Surf', E'Professional surf lessons on one of Panama''s best beginner waves. All equipment included. English and Spanish.', '5076XXX0001', '5076XXX0001', 7.421, -80.151, 'https://images.unsplash.com/photo-1455729552865-3658a5d39692?w=800&q=80', 'On request', 0, 45, 4.8, 7, 17, true, 'experience'),
('00000000-0000-0000-0000-0000000000e2', 'Venao Yoga Retreat', 'Wellness', 'Start your day with a sunrise yoga class on the beach. All levels welcome. Mats provided.', '', '', 7.422, -80.152, 'https://images.unsplash.com/photo-1575052814086-f385e2e2ad1b?w=800&q=80', 'On request', 0, 15, 4.9, 6, 10, true, 'experience'),
('00000000-0000-0000-0000-0000000000e3', 'ATV Jungle Tour', 'Adventure', 'Explore the jungle trails and hilltops of Venao on all-terrain vehicles. Epic views, muddy fun.', '5076XXX0003', '5076XXX0003', 7.420, -80.155, 'https://images.unsplash.com/photo-1533130061792-64b345e4a833?w=800&q=80', 'On request', 0, 65, 4.7, 8, 16, true, 'experience'),
('00000000-0000-0000-0000-0000000000e4', 'Fishing Trip Panama', 'Adventure', 'Deep-sea and sport fishing off Playa Venao. Catch roosterfish, tuna, mahi-mahi. All tackle included.', '5076XXX0004', '5076XXX0004', NULL, NULL, 'https://images.unsplash.com/photo-1500539100099-e16bb0070fb7?w=800&q=80', 'On request', 0, 120, 4.6, 5, 12, true, 'experience'),
-- Stays
('00000000-0000-0000-0000-0000000000s1', 'La Playa Cabinas', 'Stay', E'Simple, clean beachfront cabinas right on Playa Venao. Wake up to the sound of waves. Best location in town.', '5076XXX0010', '5076XXX0010', NULL, NULL, 'https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800&q=80', 'On request', 0, 55, 4.5, 0, 24, true, 'stay'),
('00000000-0000-0000-0000-0000000000s2', 'Venao Hostel', 'Stay', 'The social hub of Playa Venao. Dorm beds, great vibes, hammocks, shared kitchen. Surfers, backpackers, good people.', '5076XXX0011', '5076XXX0011', NULL, NULL, 'https://images.unsplash.com/photo-1555854877-bab0e564b8d5?w=800&q=80', 'On request', 0, 18, 4.3, 0, 24, true, 'stay'),
('00000000-0000-0000-0000-0000000000s3', 'Surf Camp Glamping', 'Stay', 'Luxury safari tents steps from the break. Surf packages available. The coolest sleep in Venao.', '5076XXX0012', '5076XXX0012', NULL, NULL, 'https://images.unsplash.com/photo-1510672981848-a1c4f1cb5ccf?w=800&q=80', 'On request', 0, 85, 4.7, 0, 24, true, 'stay');

